comments.body:
Xufeng's proposal on tree structure:

Augment existing P2P model with "replication-group" and "receiver-constraint-group":

```
        +--rw connectivity-constructs
        |  +--rw connectivity-construct* [id]
        |  |   +--rw id    uint32
        |  |     +--rw topology-id?              -> ../../../network-topologies/network-topology/topology-id
        |  |     +--rw src-endpoint?             -> ../../../endpoints/endpoint/endpoint-id
        |  |     +--rw dst-endpoint?             -> ../../../endpoints/endpoint/endpoint-id
        |  |     +--rw slo
        |  |     +--rw explicit-path* [tp-id]    a-->b c-->d    |    a,b,c,d
        |  |       +--rw tp-id   
        |  +--rw replication-group* [id]
        |     +--rw id                  uint32
        |     +--rw entry*              -> ../../connectivity-construct/id
        |  +--rw receiver-constraint-group* [id]
        |     +--rw id                  uint32
        |     +--rw entry*              -> ../../connectivity-construct/id
        |     +--rw te-bandwidth
        |     |  +--rw (technology)?
        |     |     +--:(generic)
        |     |        +--rw generic?   te-bandwidth

 +--rw connectivity-matrix
 |  +--rw connectivity-construct* [id]
 |     +--rw id                  uint32
 |     +--rw from
 |     |  +--rw tp-ref?               leafref
 |     +--rw to
 |     |  +--rw tp-ref?               leafref
 |     +--rw underlay {te-topology-hierarchy}?
 |     +--rw path-constraints
 |     +--rw optimizations
 |  +--rw replication-group* [id]
 |     +--rw id                  uint32
 |     +--rw entry*              -> ../../connectivity-construct/id
 |  +--rw receiver-constraint-group* [id]
 |     +--rw id                  uint32
 |     +--rw entry*              -> ../../connectivity-construct/id
 |     +--rw te-bandwidth
 |     |  +--rw (technology)?
 |     |     +--:(generic)
 |     |        +--rw generic?   te-bandwidth


Examples:

1) P2P
   NSE3 <-> NSC7
   NSE4 -> NSE8

{
  "connectivity-matrix": {
    "connectivity-construct": [
      "id": 1,
      "from": {
        "tp-ref": "NSE3"
      },
      "to": {
        "tp-ref": "NSE7"
      }
    ],
    "connectivity-construct": [
      "id": 2,
      "from": {
        "tp-ref": "NSE7"
      },
      "to": {
        "tp-ref": "NSE3"
      }
    ],
    "connectivity-construct": [
      "id": 3,
      "from": {
        "tp-ref": "NSE4"
      },
      "to": {
        "tp-ref": "NSE8"
      }
    ]
  }
}


2) P2MP
   NSE5 -> {NSC9, NSE10}

{
  "connectivity-matrix": {
    "connectivity-construct": [
      "id": 1,
      "from": {
        "tp-ref": "NSE5"
      },
      "to": {
        "tp-ref": "NSE9"
      }
    ],
    "connectivity-construct": [
      "id": 2,
      "from": {
        "tp-ref": "NSE5"
      },
      "to": {
        "tp-ref": "NSE10"
      }
    ],
    "replication-group": [
      "id": 1,
      "entry": [1, 2]
    ]
  }
}


3) MP2MP
   {NSE14, NSE15} -> {NSE16, NSE17}

{
  "connectivity-matrix": {
    "connectivity-construct": [
      "id": 1,
      "from": {
        "tp-ref": "NSE14"
      },
      "to": {
        "tp-ref": "NSE16"
      }
    ],
    "connectivity-construct": [
      "id": 2,
      "from": {
        "tp-ref": "NSE14"
      },
      "to": {
        "tp-ref": "NSE17"
      }
    ],
    "connectivity-construct": [
      "id": 3,
      "from": {
        "tp-ref": "NSE15"
      },
      "to": {
        "tp-ref": "NSE16"
      }
    ],
    "connectivity-construct": [
      "id": 4,
      "from": {
        "tp-ref": "NSE15"
      },
      "to": {
        "tp-ref": "NSE17"
      }
    ],
    "replication-group": [
      "id": 1,
      "entry": [1, 2]
    ],
    "replication-group": [
      "id": 1,
      "entry": [3, 4]
    ],
    "receiver-constraint-group": [
      "id": 1,
      "entry": [1, 3]
    ],
    "receiver-constraint-group": [
      "id": 1,
      "entry": [2, 4]
    ]
  }
}


3) A2A
   {NSE1, NSE2, NSE6} -> {NSE1, NSE2, NSE6}

{
  "connectivity-matrix": {
    "connectivity-construct": [
      "id": 1,
      "from": {
        "tp-ref": "NSE1"
      },
      "to": {
        "tp-ref": "NSE2"
      }
    ],
    "connectivity-construct": [
      "id": 2,
      "from": {
        "tp-ref": "NSE1"
      },
      "to": {
        "tp-ref": "NSE6"
      }
    ],
    "connectivity-construct": [
      "id": 3,
      "from": {
        "tp-ref": "NSE2"
      },
      "to": {
        "tp-ref": "NSE1"
      }
    ],
    "connectivity-construct": [
      "id": 4,
      "from": {
        "tp-ref": "NSE2"
      },
      "to": {
        "tp-ref": "NSE6"
      }
    ],
    "connectivity-construct": [
      "id": 5,
      "from": {
        "tp-ref": "NSE6"
      },
      "to": {
        "tp-ref": "NSE1"
      }
    ],
    "connectivity-construct": [
      "id": 6,
      "from": {
        "tp-ref": "NSE6"
      },
      "to": {
        "tp-ref": "NSE2"
      }
    ]
  }
}
```

@danielkinguk , @dancecca , @sergiobelotti and me have had a call to review the figures in [draft-ietf-teas-applicability-actn-slicing](https://datatracker.ietf.org/doc/draft-king-teas-applicability-actn-slicing/)

These are the proposed new figures:

[actn-slicing-figures-01.txt](https://github.com/ietf-ccamp-wg/ietf-ccamp-yang-otn-slicing/files/8173196/actn-slicing-figures-01.txt)

Align with the new module name:

```suggestion
     namespace "urn:ietf:params:xml:ns:yang:ietf-transport-network-slice";
     prefix "tns";
```
